package com.example.knowledgecollector.web.security;
import com.example.knowledgecollector.application.security.UserService;import com.example.knowledgecollector.web.api.*;import jakarta.servlet.http.HttpServletRequest;import org.springframework.security.core.Authentication;import org.springframework.web.bind.annotation.*;import java.util.Map;
@RestController @RequestMapping("/api/v1/profile") public class ProfileController {private final UserService users;public ProfileController(UserService users){this.users=users;}@GetMapping public ApiResponse<?>profile(Authentication a,HttpServletRequest r){var c=users.credentials(a.getName());return ApiResponse.success(Map.of("id",c.id(),"username",c.username(),"displayName",c.displayName(),"role",c.role(),"enabled",c.enabled()),cid(r));}@PostMapping("/password")public ApiResponse<?>password(@RequestBody Map<String,String>b,Authentication a,HttpServletRequest r){users.changePassword(a.getName(),b.get("currentPassword"),b.get("newPassword"));return ApiResponse.success(Map.of("changed",true),cid(r));}private String cid(HttpServletRequest r){return(String)r.getAttribute(CorrelationIdFilter.ATTRIBUTE_NAME);}}
